INSERT INTO `products` (`sort_ordine`, `id`, `name`, `price`, `lungime_cm`, `latime_cm`, `img`, `description`, `preview`, `stock`, `created_at`, `active`, `updated_at`, `deleted_at`, `diameter_cm`, `material`, `category`) VALUES
(2, 31, 'Mocheta Dreptunghiulara 2', 0, 160.00, 100.00, 'Image1.png', 'Glifele - semnături ale puterilor angelice, sigilii din cărți secrete despre puterile ființelor angelice și celeste, mandale ale rugăciunilor și mantrelor, conferă acestui covor modelele sale unice. Acest covor-artefact este ca un talisman pentru noroc, fericire și sănătate în destinul oricui îndrăznește să-l ia în casa, apartamentul sau biroul său.', '', 1, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, '', 'PsyGeometry'),
(5, 32, 'Mocheta Dreptunghiulara 5', 0, 160.00, 100.00, 'Image2.png', 'O lucrare personală a autorului, Sergey Danshin. Un Labirint al Oportunităților. Acest covor este conceput pentru a intra în afaceri complexe și a scăpa de situații dificile. Pare imposibil să scapi de soarte încâlcite, cazuri încâlcite și matrici complexe, dar acest covor arată că o persoană este un labirint. Covorul este conceput pentru a scăpa de situații foarte dificile și confuze din viață. 6.\nProtejează-mă în afaceri, în dragoste, învăluie-mă în veșminte invizibile, astfel încât dușmanii vizibili și invizibili să nu mă observe. Acest covor gri va dezvălui planurile manipulatorului. Culoarea fericirii îl va învălui imperceptibil pe oricine îl cumpără.\n', '', 1, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, '', 'PsyGeometry'),
(4, 33, 'Mocheta Dreptunghiulara 4', 0, 160.00, 100.00, 'Image3.png', 'Runarium. Simbolurile runice sunt destinate succesului în lumea financiară și lucrului cu colegi buni.\nRunica este compusă din 9 rune. Acestea conțin un cod ascuns al norocului pentru oricine îndrăznește să-l aducă la viață la birou, acasă sau oriunde altundeva este atât de necesară.\nCumpără o picătură, un covor miraculos și nu vei regreta banii, iar toată lumea are nevoie de succes financiar la locul de muncă.\n', NULL, 1, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, '', 'PsyGeometry'),
(6, 34, 'Mocheta Dreptunghiulara 6', 0, 160.00, 100.00, 'Image4.png', 'Protejează-mă în afaceri, în dragoste, învăluie-mă în veșminte invizibile, astfel încât dușmanii vizibili și invizibili să nu mă observe. Acest covor gri va dezvălui planurile manipulatorului. Culoarea fericirii îl va învălui imperceptibil pe oricine îl cumpără.', '', 1, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, '', 'PsyGeometry'),
(7, 35, 'Mocheta Dreptunghiulara 7', 0, 160.00, 100.00, 'Image5.png', 'Ziua este foarte aproape când sănătatea și protecția împotriva bolilor mintale vor intra în casa numită trupul meu. Sănătatea minții și a trupului, puterea Zeității ascunse care învăluie icoanele cu credință, speranță și iubire. Formele psihogeometrice afectează pietrele, plasticul și sticla din casă. Metalul și oxizii metalici. Dacă există plante sau flori, acestea vor fi umplute de puterea acestui covor. Astfel, o persoană își va îmbunătăți bunăstarea.', '', 1, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, '', 'PsyGeometry'),
(8, 36, 'Mocheta Dreptunghiulara 8', 0, 160.00, 100.00, 'Image6.png', 'Tot ce are legătură cu munca și dorințele tale în această muncă este conținut în trei simboluri și în această formă psihogeometrică. Acest covor talisman rezolvă și ajută la rezolvarea problemelor periculoase la locul de muncă.\n\nDezvăluie secretul celor care îl ascund. Ajută în multe probleme.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(9, 37, 'Mocheta Dreptunghiulara 9', 0, 160.00, 100.00, 'Image7.png', 'Acest covor conține multe secrete. Ascunde secretele oamenilor și ale zeilor care sporesc abilitățile umane. Simbolismul și geometria lor, în numeroasele lor forme energo-informaționale, oferă oamenilor oportunități minunate de a se descoperi acolo unde este nevoie. Acest covor conține secretele lumii. Cumpără, deschide și folosește.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(10, 38, 'Mocheta Dreptunghiulara 10', 0, 160.00, 100.00, 'Image8.png', 'Runascript, runestav, labirint runic sub formă de mandală. Acest secret runic este un asistent în afaceri, în încheierea contractelor, în descoperirea conspirațiilor. Galbenul este comunicarea, un aliat, un secretar, un consilier, comunicarea cu diferite tipuri de oameni pentru a rezolva problemele legate de muncă. Finanțele și bogăția sunt scopul său final. Dar fiecare covor conține puterea invizibilă a lui Dumnezeu, Creatorul a toate. Ia-l, cumpără-l și bucură-te că ai putut atinge secretele problemelor invizibile.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 39, 'Mocheta Dreptunghiulara 11', 0, 160.00, 100.00, 'Image9.png', 'Compoziție din 3 sigilii: unește puterea pentru service, afacere, clientelă bună, foarte bun la vânzarea produselor, de asemenea are protecție împotriva hoților fizici sau energetici. Forma de cruce face stabilitate. ', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 40, 'Mocheta Dreptunghiulara 12', 0, 160.00, 100.00, 'Image10.png', 'Talisman realizat din compoziția a 9 runascripte. Potențează oricare dorință pentru realizarea ei.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 41, 'Mocheta Dreptunghiulara 13', 0, 160.00, 100.00, 'Image11.png', 'Talisman pentru familie, iubire, copii; aceste forme arcuite au în structură milioane tipuri de cuvinte de putere, mantre, rugăciuni și puterea îngerilor. ', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 42, 'Mocheta Dreptunghiulara 14', 0, 160.00, 100.00, 'Image12.png', ' În fața Sfintei Treimi a fost creată o formă vie, pentru conducerea oricărei forme de bogăție. Este un mare talisman care, împreună cu puterea divină, ajută să fi bogat, iar dacă e nevoie, în mod secret. Abundență.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 43, 'Mocheta Dreptunghiulara 15', 0, 160.00, 100.00, 'Image13.png', 'Psihogeometria sacră și numerologia secretă unește codurile cu tot ceea ce își poate dori un om în viață. ', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 44, 'Mocheta Dreptunghiulara 16', 0, 160.00, 100.00, 'Image14.png', 'Armonie în cuplu, pentru familie, armonie și pace în casă, ajută tinerilor care își doresc să facă un cuplu.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 45, 'Mocheta Dreptunghiulara 17', 0, 160.00, 100.00, 'Image15.png', 'Rezolvarea situațiilor legate de partea financiară: datorii, rate la bancă, împrumuturi etc.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 46, 'Mocheta Dreptunghiulara 18', 0, 160.00, 100.00, 'Image16.png', 'Puterea din sigiliul îngerului protector. Ghidează și protejează de aripile invizibile ale acestui înger. Îngerul este imparțial ', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 47, 'Mocheta Dreptunghiulara 19', 0, 160.00, 100.00, 'Image17.png', 'Numele Lui Dumnezeu reflectează în oricare celulă a corpului. Sunetul este HRI. Vindecare, protecție, regenerare, echilibru. Mandala HRI și mantra, are legătură cu numele Hristos din vechea limbă greacă. În Himalaya monograma HRI este centrul lotusului vieții pe care stă Creatorul.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 48, 'Mocheta Dreptunghiulara 20', 0, 160.00, 100.00, 'Image18.png', 'Mandala artefact a Serafimului Elemiah, cel care ajută la succesul professional, spiritul antreprenorial, stabilitate financiară și protejează în călătorii.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 49, 'Mocheta Dreptunghiulara 21', 0, 160.00, 100.00, 'Image19.png', 'Mandala cu Serafimul Mahasiah, cel care promovează înțelegerea, toleranța și abilitatea de a trăi în pace cu lumea, susține învățarea, știința și înțelegerea simbolisticii din mesajele viselor.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 50, 'Mocheta Dreptunghiulara 22', 0, 160.00, 100.00, 'Image20.png', 'Puterea zeilor, a divinităților, Sfintei Treimi. Mare artefact cu mandale, semnături, simboluri, psihogeometrie pentru tot ceea ce îi poate dori un om în viața lui. Se activează cu mantra HRI', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 51, 'Mocheta Dreptunghiulara 23', 0, 160.00, 100.00, 'Image21.png', 'Puterea divinităților în forme diferite, este și în acest minunat covor. Iubire, sănătate, prosperitate, protecție, îndrumare divină, acestea sunt câteva dintre beneficiile acestui artefact complex.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 52, 'Mocheta Dreptunghiulara 24', 0, 160.00, 100.00, 'Image22.png', 'Mocheta artefact pentru rezolvarea situațiilor complicate atât în familie cât și la servici sau în societate. Fericire și success împreună cu iluminare înmulțește puterea în oricare fie personal fie comun.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 53, 'Mocheta Dreptunghiulara 25', 0, 160.00, 100.00, 'Image23.png', 'Un nexus biocibernetic de formule runice și o structură sigilistică au conectat ușor un câmp țesut dintr-o multitudine de formule în jurul unei idei centrale. Tot ce și-ar putea dori cineva este conținut în acest desen mistic. Rugăciuni, mantre, nume de zei, rune, sigilii, nume de îngeri, formule pentru vindecarea bolilor complexe, soluții la dificultăți financiare - întregul câmp al miracolelor a unit 2.000 de structuri sinusoidale psihogeometrice și numerologice. Un generator, o forță.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 54, 'Mocheta Dreptunghiulara 26', 0, 160.00, 100.00, 'Image24.png', 'Acest model roșu închis conectează două personalități divine, Lakshmi și Narayana. Ele sunt ca mierea pentru viața de pe planeta noastră. Dragostea și puterea lor ajută în multe demersuri.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 55, 'Mocheta Dreptunghiulara 27', 0, 160.00, 100.00, 'Image25.png', 'Nu poți fi prins când ideea ta devine realitate. Acest talisman sporește abilitățile și te ajută să iei ceea ce este cel mai necesar dintr-o idee, o fantezie sau un plan virtual și să-l aduci la viață. Îndrăznește și ia-l. Este asistentul tău în ideile și realizările tale.\n', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 56, 'Mocheta Dreptunghiulara 28', 0, 160.00, 100.00, 'Image26.png', 'Există întotdeauna o putere angelică invizibilă în toate demersurile. Codul îngeresc și numele său, Yeliel, sunt o adevărată forță invizibilă atât în afaceri, cât și în armonia vetrei familiei.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 57, 'Mocheta Dreptunghiulara 29', 0, 160.00, 100.00, 'Image27.png', ' Un adevărat artefact al forțelor naturale ale Zeilor și ale Creatorului însuși. Mandalele personalităților divine și fire aurii și galbene îți vor învălui ideile și le vor aduce la viață. \n', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 58, 'Mocheta Dreptunghiulara 30', 0, 160.00, 100.00, 'Image28.png', 'Un artefact al destinului și al puterii timpului sunt unite în acest ansamblu. Câteva mii de coduri divine într-un singur loc. Micile mandale din stânga și din dreapta reprezintă rugăciunea noastră, Rugăciunea Domnească, iar în centru, un adevărat scut te protejează de pericolele sorții.\n', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 59, 'Mocheta Dreptunghiulara 31', 0, 160.00, 100.00, 'Image29.png', 'Cărțile antice vorbesc despre corăbii inscripționate cu anumite semne. Iată două sigilii. În partea de sus se află un sigiliu care protejează de hoți și tâlhari. În partea de jos se află un semn, un sigiliu care îndepărtează cu blândețe energia rea dintr-o persoană, o vrajă. Curăță și îmbunătățește aura și psihicul. Curăță de energia negativă. Împreună, aceste sigilii ajută pe cineva să se elibereze de negativitate și de oamenii răi.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 60, 'Mocheta Dreptunghiulara 32', 0, 160.00, 100.00, 'Image30.png', 'Putere protectoare enormă. Se numește HAGISPER. În orice situație dificilă, provocatoare, este un ajutor. Geometria sa salvează de situațiile rele. Eliberează calea și îmbunătățește viața și situațiile unei persoane.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 61, 'Mocheta Dreptunghiulara 33', 0, 160.00, 100.00, 'Image31.png', 'Un artefact derivat din himalayană, tibetană, sanscrită și din propriile noastre rugăciuni și mantre. Conține energia a câteva zeci de coduri psihogeometrice și simboluri numerologice, transformate în puterile ființelor divine. Este perfect pentru casă și birou, pentru copii și adulți. Acest artefact conectează destinele și puterile Sfintei Treimi și pe cei care le sunt fideli, atât în dragoste, cât și în afaceri, precum și în soluții creative. Universul aude și vede și te ajută în viață.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 62, 'Mocheta Dreptunghiulara 34', 0, 160.00, 100.00, 'Image32.png', 'Labirint psihogeometric al puterii îngerului Elemiah. Un asistent în viață, în multe privințe.\n', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 63, 'Mocheta Dreptunghiulara 35', 0, 160.00, 100.00, 'Image33.jpg', 'Este dificil să găsești persoana potrivită pentru muncă, pentru viață, pentru dragoste, pentru prietenie adevărată. Iată-l. Acest artefact te conectează cu cel pe care ți-ai dori să-l vezi alături.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 64, 'Mocheta Dreptunghiulara 36', 0, 160.00, 100.00, 'Image34.jpg', 'Acest mic miracol este creat dintr-o mantră a norocului. Aceasta este puterea sa. Noroc și avere în afaceri și în necazurile vieții.\n', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 65, 'Mocheta Dreptunghiulara 37', 0, 160.00, 100.00, 'Image35.png', 'Dacă ceva este ascuns, există un secret, dacă trebuie să găsești ceva sau pe cineva, acest artefact te va ajuta. Ia-l și verifică-l singur. Dar nu-l folosi de prea multe ori odată. Și oricine este ascuns în această imagine are nevoie de odihnă și acumulare de forță pentru data viitoare. Ajută la găsirea a ceea ce este ascuns la nivel fizic, mental și intelectual.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 66, 'Mocheta Dreptunghiulara 38', 0, 160.00, 100.00, 'Image36.png', 'Când Matricea te absoarbe, acest artefact te salvează. O gură de oxigen de la manipularea conștiinței tale.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 67, 'Mocheta Dreptunghiulara 39', 0, 160.00, 100.00, 'Image37.png', 'Dacă cineva te deranjează, această imagine nu este simplă. Te va curăța de negativitate, îți va îmbunătăți sănătatea, te va ajuta să găsești un asistent și te va proteja atât pe drum, cât și oriunde. Acest artefact conține multe rugăciuni și mantre. Modelele lor psihogeometrice formează un câmp energetic invizibil pe mulți kilometri.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 68, 'Mocheta Dreptunghiulara 40', 0, 160.00, 100.00, 'Image38.png', 'Crește puterea pentru sarcina la îndemână. Oferă putere pentru dorință. Labirintul său este țesut din fire. Aceste noduri de fire creează energia necesară pentru ceea ce este dorit. Ajută plantele, animalele și oamenii.\n', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 69, 'Mocheta Dreptunghiulara 41', 0, 160.00, 100.00, 'Image39.png', 'Un semn secret unic al civilizației lor orientale antice. Secretul său dezvăluie secrete ascunse în pământ și în oameni. Ajută în sate, la locul de muncă și pe drum.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1, 70, 'Mocheta Dreptunghiulara 1', 0, 160.00, 100.00, 'Image40.png', 'Conexiunea liniilor ondulate reprezintă uniunea a două persoane. Pe un fundal albastru, reprezintă libertatea în relații, dar și credința în unitate. Formele în formă de cruce roșie reprezintă dezvăluirea secretelor în familie și la locul de muncă.', '', 1, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, '', 'PsyGeometry'),
(1000, 71, 'Mocheta Dreptunghiulara 42', 0, 160.00, 100.00, 'Image41.png', ' Peste 2 milioane de microstructuri psihogeometrice, numerologice și matriceale sunt combinate în acest artefact. Pentru noroc, sănătate și iluminare. Tot ce este în întuneric va fi iluminat și vizibil. Îmbunătățește superputerile. Crește puterea și rezistența. Numeroase rugăciuni, cuvinte, mantre și simboluri sunt combinate în acest spațiu multidimensional, unite în această pictură, în acest artefact.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 72, 'Mocheta Dreptunghiulara 43', 0, 160.00, 100.00, 'Image42.png', 'Runa URUZ, un ajutor minunat în deblocarea capacității de a rezolva probleme complexe.\n', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 73, 'Mocheta Dreptunghiulara 44', 0, 160.00, 100.00, 'Image43.png', '2 glife - semnături ale puterii și 1 formulă de scriere runică. Pentru tranzacții financiare. Pentru muncă. Ajută în treburile unei companii sau asociații. Bun pentru fabrici și uzine. Este bun dacă este pe o mașină. Ajută pe oricine să dezvolte puterea de a conduce proiecte mici și mari. Această putere permite 100% muncă.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 74, 'Mocheta Dreptunghiulara 45', 0, 160.00, 100.00, 'Image44.png', 'Putere angelică enormă. Ajută acolo unde pare să nu existe putere. Va da putere și va ajuta la ieșirea din situații periculoase. Va îmbunătăți sănătatea și va da putere.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 75, 'Mocheta Dreptunghiulara 46', 0, 160.00, 100.00, 'Image45.png', 'Un artefact mare ajutor. În yum, rugăciunile și mantrele sunt combinate într-unul singur. Pentru cei cărora le place să își asume riscuri și să câștige. Pentru victorie.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 76, 'Mocheta Dreptunghiulara 47', 0, 160.00, 100.00, 'Image46.png', 'Toate cuvintele Psalmului 22 sunt traduse în numere, iar aceste numere sunt traduse în psihogeometrie. Psalmul 22 te va salva și te va ajuta în viață.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 77, 'Mocheta Dreptunghiulara 48', 0, 160.00, 100.00, 'Image47.png', 'Uneori pare că totul în familia ta este exact așa cum îți dorești. Dar nu este adevărat. Toate planetele și stelele au propriul lor loc spațial personal. Acest soare te va încălzi și te va ajuta să te simți mai apropiat de cei pe care îi iubești.\n', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 78, 'Mocheta Dreptunghiulara 49', 0, 160.00, 100.00, 'Image48.png', 'Yantra plane in cifre', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 79, 'Mocheta Dreptunghiulara 50', 0, 160.00, 100.00, 'Image49.png', 'Frica este atunci când nu poți să-ți dai seama de unde provine. Dar dacă o faci? Această formă este foarte magică; te ajută să accepți frica ca o forță care te schimbă și îți oferă o oportunitate reală de a transforma frica în curaj. Iubește și înțelege cum să nu depășești frica, ci să o modifici, să o purifici și să o folosești pentru casă, familie, muncă și atingerea obiectivelor tale.\n', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 80, 'Mocheta Dreptunghiulara 51', 0, 160.00, 100.00, 'Image50.png', 'Există o putere unică pentru rezolvarea problemelor și primirea ajutorului de la Dumnezeul triunic. Are o formă și un suflet în ea. Aceasta este o altă parte a lui Dumnezeu. Numele său este Kubera. El îți va veni întotdeauna în ajutor dacă ai probleme cu finanțele, banii sau bogăția. Dorința de bogăție vine de la slujitorul lui Dumnezeu, din partea sa, al cărui nume este Kubera. Acest artefact ajută la muncă, documente, bani și autocontrol. 52 - Acesta nu este doar un labirint; conține o conexiune psihogeometrică ce îți va îmbunătăți bunăstarea și sănătatea. Acest labirint de linii și noduri conține un secret numerologic și psihogeometric ascuns, puterea lui Dumnezeu și puterea minții care te purifică pe tine și pe cei care intră în contact cu tine și cu această imagine.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 81, 'Mocheta Dreptunghiulara 52', 0, 160.00, 100.00, 'Image51.png', 'Acesta nu este doar un labirint; conține o conexiune psihogeometrică ce îți va îmbunătăți bunăstarea și sănătatea. Acest labirint de linii și noduri conține un secret numerologic și psihogeometric ascuns, puterea lui Dumnezeu și puterea minții care te purifică pe tine și pe cei care intră în contact cu tine și cu această imagine.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 82, 'Mocheta Dreptunghiulara 53', 0, 160.00, 100.00, 'Image52.png', 'Zeii și Zeițele sunt ajutoare de la Dumnezeu, de la Creator, de la Duhul Sfânt. Sunt mulți dintre ei. Îngerii și sfinții din toate religiile lumii sunt el, ochii, mâinile, urechile sale, gustul și mirosul său. Care imagine sinusoidală a personalității divine va ajuta acolo unde pare să nu existe nicio ieșire? Un artefact pentru rezolvarea dificultăților atât în ​​sănătate, cât și în viață.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 83, 'Mocheta Dreptunghiulara 54', 0, 160.00, 100.00, 'Image53.png', 'Un nod foarte complex al vieții poate fi dezlegat doar de cel care l-a legat. Karma și soarta sunt controlate de cineva. Așadar, EL sau EA te vor ajuta să dezlegi nodurile cosmice, astrologice și fatidice ale vieții tale. 55 - Când familia sau rudele tale au nevoie de ordine, acest artefact va ajuta la îmbunătățirea ei. Puterea angelică și mâna invizibilă a lui Dumnezeu vor intra în casa ta și te vor ajuta în relațiile tale cu prietenii, familia și cei dragi.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 84, 'Mocheta Dreptunghiulara 55', 0, 160.00, 100.00, 'Image54.png', '\nCând familia sau rudele tale au nevoie de ordine, acest artefact te va ajuta să o îmbunătățești. Puterea angelică și mâna invizibilă a lui Dumnezeu vor intra în casa ta și te vor ajuta în relațiile cu prietenii, familia și cei dragi.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 85, 'Mocheta Dreptunghiulara 56', 0, 160.00, 100.00, 'Image55.png', 'Există multe secrete pe pământ. Acesta este secretul sigiliilor. Aceste semne puternice ale puterii au ajuns la noi din diferite civilizații. Sunt folosite în multe scopuri diferite pe pământ. Sunt ca o unealtă. În mâinile unei persoane întunecate, sunt periculoase, dar în mâinile unei persoane strălucitoare, sunt un miracol pentru tot ceea ce și-ar putea dori cineva. Fiecare sigiliu este foarte important. De-a lungul a sute de ani, aceste semne nu și-au pierdut moei-ul și puterea.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 86, 'Mocheta Dreptunghiulara 57', 0, 160.00, 100.00, 'Image56.png', 'Când o persoană are nevoie de abilități, competențe sau superputeri, această imagine o ajută să le dobândească. Aceasta este puterea cuvintelor în formă și forma în ceea ce vezi. Privește asta pentru un minut și, dacă este un covor, mergi pe el și gândește-te la ce ai nevoie. Aceasta este magia divină a cuvintelor sub forma unei mandale.\n', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 87, 'Mocheta Dreptunghiulara 58', 0, 160.00, 100.00, 'Image57.png', 'Mandala Îngerească. Vei fi protejat și, dacă este necesar, vei deveni vizibil sau invizibil pentru toată lumea. Această mandală, pe un fundal de cer albastru, dezvăluie secretele naturii, atât umane, cât și pământești. Caută și găsește.\n', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 88, 'Mocheta Dreptunghiulara 59', 0, 160.00, 100.00, 'Image58.jpg', 'Mandala Îngerească este un protector și un ajutor în viața ta. Aceste modele au fost create personal. Conțin codul și puterea îngerului. Este frumoasă pentru casă, familie sau birou. Și este foarte bună pentru vindecare și vindecare atât fizică, cât și mentală.\n', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 89, 'Mocheta Dreptunghiulara 60', 0, 160.00, 100.00, 'Image59.png', ' Când simți că nu poți trece o linie, când nu ești auzit sau înțeles, când îți dorești atât bani, cât și respect, această imagine puternică îți va da putere, curaj și capacitatea de a depăși obstacolele și de a realiza ceea ce pare imposibil. Codul angelic numerologic și psihogeometric sub forma acestei structuri nodale îți va oferi acest lucru. Un artefact minunat de ajutor și putere angelică divină.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(1000, 90, 'Mocheta Dreptunghiulara 61', 0, 160.00, 100.00, 'Image60.png', 'Atunci când simți că ai ajuns la limită, că vocea ta nu este auzită și că drumul din fața ta pare blocat, această imagine puternică îți poate aduce încredere, echilibru și forța de a merge mai departe. Prin simbolistica sa numerologică și geometrică, această structură nodală transmite energie, protecție și susținere interioară. Este un artefact deosebit, creat pentru a inspira curaj, putere și depășirea obstacolelor.', NULL, 0, '2026-02-18 08:58:34', 1, NULL, NULL, 0.00, NULL, 'PsyGeometry'),
(-1000, 91, 'Ingeras 1', 6, 5.00, 2.00, 'Image61.png', 'Îngerul Păcii este prevăzut cu agățătoare din turnare. Este turnat din ipsos de modelaj și apă, in sistem handmade. \nȘtim că Îngerii sunt ajutoare de lumină ce ne susțin mereu! Eu sunt cei care ne transmit gândul bun și Pacea! 💕', NULL, 124, '2026-02-23 09:54:20', 1, NULL, NULL, 0.00, NULL, 'Ingerasi'),
(0, 92, 'Ingeras 2', 6, 5.00, 2.00, 'Image62.png', 'Îngerul Păcii este prevăzut cu agățătoare din turnare. Este turnat din ipsos de modelaj și apă, in sistem handmade. \nȘtim că Îngerii sunt ajutoare de lumină ce ne susțin mereu! Eu sunt cei care ne transmit gândul bun și Pacea! 💕', NULL, 10, '2026-02-23 07:54:20', 1, NULL, NULL, 0.00, NULL, 'Ingerasi'),
(0, 93, 'Ingeras 3', 6, 5.00, 2.00, 'Image63.png', 'Îngerul Păcii este prevăzut cu agățătoare din turnare. Este turnat din ipsos de modelaj și apă, in sistem handmade. \nȘtim că Îngerii sunt ajutoare de lumină ce ne susțin mereu! Eu sunt cei care ne transmit gândul bun și Pacea! 💕', NULL, 10, '2026-02-23 07:54:20', 1, NULL, NULL, 0.00, NULL, 'Ingerasi'),
(0, 94, 'Ingeras 4', 6, 5.00, 2.00, 'Image64.png', 'Îngerul Păcii este prevăzut cu agățătoare din turnare. Este turnat din ipsos de modelaj și apă, in sistem handmade. \nȘtim că Îngerii sunt ajutoare de lumină ce ne susțin mereu! Eu sunt cei care ne transmit gândul bun și Pacea! 💕', NULL, 10, '2026-02-23 07:54:20', 1, NULL, NULL, 0.00, NULL, 'Ingerasi'),
(0, 95, 'Ingeras 5', 6, 5.00, 2.00, 'Image65.png', 'Îngerul Păcii este prevăzut cu agățătoare din turnare. Este turnat din ipsos de modelaj și apă, in sistem handmade. \nȘtim că Îngerii sunt ajutoare de lumină ce ne susțin mereu! Eu sunt cei care ne transmit gândul bun și Pacea! 💕', NULL, 10, '2026-02-23 07:54:20', 1, NULL, NULL, 0.00, NULL, 'Ingerasi'),
